const e=JSON.parse('{"key":"v-289f552e","path":"/%E5%89%8D%E7%AB%AF/css/2.html","title":"CSS盒子模型","lang":"zh-CN","frontmatter":{"title":"CSS盒子模型","icon":"edit","date":"2023-07-03T00:00:00.000Z","category":["前端"],"tag":["前端","CSS"],"star":true,"description":"盒子模型 标准文档流: HTML语言由标签构成，浏览器的程序会对标签进行解析，每解析一个标签，就会在浏览器窗口中将它“画”出来，即完成元素的布局。 一个元素，浏览器会把它认为是一个矩形。浏览器会将矩形从左向右，从上向下按照顺序完成对元素的布局，这个顺序流就是标准文档流 盒子模型: 所有文档元素都生成一个矩形框，描述一个元素在文档布局中所占的空间大小，称为元素盒子(element box)。 每个框影响着其他元素框的位置和大小，理解这些“盒子”的基本原理，是我们使用 CSS 实现准确布局、处理元素排列的关键。 盒子模型定义了盒的每个部分：margin（外边距）, border（边框）, padding（内边距）, content（内容，width+height）。它们合在一起就可以创建我们在页面上看到的内容。","head":[["meta",{"property":"og:url","content":"https://skym1.gitee.io/%E5%89%8D%E7%AB%AF/css/2.html"}],["meta",{"property":"og:site_name","content":"Skyme的博客"}],["meta",{"property":"og:title","content":"CSS盒子模型"}],["meta",{"property":"og:description","content":"盒子模型 标准文档流: HTML语言由标签构成，浏览器的程序会对标签进行解析，每解析一个标签，就会在浏览器窗口中将它“画”出来，即完成元素的布局。 一个元素，浏览器会把它认为是一个矩形。浏览器会将矩形从左向右，从上向下按照顺序完成对元素的布局，这个顺序流就是标准文档流 盒子模型: 所有文档元素都生成一个矩形框，描述一个元素在文档布局中所占的空间大小，称为元素盒子(element box)。 每个框影响着其他元素框的位置和大小，理解这些“盒子”的基本原理，是我们使用 CSS 实现准确布局、处理元素排列的关键。 盒子模型定义了盒的每个部分：margin（外边距）, border（边框）, padding（内边距）, content（内容，width+height）。它们合在一起就可以创建我们在页面上看到的内容。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-08-28T01:15:29.000Z"}],["meta",{"property":"article:author","content":"Skyme"}],["meta",{"property":"article:tag","content":"前端"}],["meta",{"property":"article:tag","content":"CSS"}],["meta",{"property":"article:published_time","content":"2023-07-03T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-08-28T01:15:29.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"CSS盒子模型\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-07-03T00:00:00.000Z\\",\\"dateModified\\":\\"2023-08-28T01:15:29.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Skyme\\",\\"url\\":\\"https://skym1.gitee.io\\"}]}"]]},"headers":[{"level":2,"title":"盒子模型","slug":"盒子模型","link":"#盒子模型","children":[{"level":3,"title":"盒子模型的组成","slug":"盒子模型的组成","link":"#盒子模型的组成","children":[]},{"level":3,"title":"相关属性:","slug":"相关属性","link":"#相关属性","children":[]},{"level":3,"title":"盒子模型大小计算","slug":"盒子模型大小计算","link":"#盒子模型大小计算","children":[]},{"level":3,"title":"CSS元素分类","slug":"css元素分类","link":"#css元素分类","children":[]},{"level":3,"title":"表格:","slug":"表格","link":"#表格","children":[]},{"level":3,"title":"表单:","slug":"表单","link":"#表单","children":[]}]}],"git":{"createdTime":1693185329000,"updatedTime":1693185329000,"contributors":[{"name":"Skym1","email":"412399240@qq.com","commits":1}]},"readingTime":{"minutes":8.3,"words":2490},"filePathRelative":"前端/css/2.md","localizedDate":"2023年7月3日","excerpt":"<h2> 盒子模型</h2>\\n<ol>\\n<li>\\n<p>标准文档流:</p>\\n<p>HTML语言由标签构成，浏览器的程序会对标签进行解析，每解析一个标签，就会在浏览器窗口中将它“画”出来，即完成元素的布局。<br>\\n一个元素，浏览器会把它认为是一个矩形。浏览器会将矩形从左向右，从上向下按照顺序完成对元素的布局，这个顺序流就是标准文档流</p>\\n</li>\\n<li>\\n<p>盒子模型:</p>\\n<p>所有文档元素都生成一个矩形框，描述一个元素在文档布局中所占的空间大小，称为元素盒子(element box)。<br>\\n每个框影响着其他元素框的位置和大小，理解这些“盒子”的基本原理，是我们使用 CSS 实现准确布局、处理元素排列的关键。<br>\\n盒子模型定义了盒的每个部分：margin（外边距）, border（边框）, padding（内边距）, content（内容，width+height）。它们合在一起就可以创建我们在页面上看到的内容。</p>\\n</li>\\n</ol>","autoDesc":true}');export{e as data};
